import React, { useEffect, useState } from 'react';
import axios from 'axios';

function UserPage() {
  const [users, setUsers] = useState([]);
  const [formData, setFormData] = useState({ name: '', email: '' });
  const [editUser, setEditUser] = useState(null);
const [search, setSearch] = useState('');

  // Fetch users from backend
  useEffect(() => {
    fetchUsers();
  }, []);

  useEffect(() => {
  if (editUser) {
    setFormData({ name: editUser.name, email: editUser.email });
  }
}, [editUser]);

  const fetchUsers = async () => {
    const res = await axios.get('http://localhost:5000/api/users');
    setUsers(res.data);
  };

  // Handle form field changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Handle form submit
 const handleSubmit = async (e) => {
  e.preventDefault();
  if (!formData.name || !formData.email) return alert('Please fill all fields');

  if (editUser) {
    await axios.put(`http://localhost:5000/api/users/${editUser._id}`, formData);
    setEditUser(null);
  } else {
    await axios.post('http://localhost:5000/api/users', formData);
  }

  setFormData({ name: '', email: '' });
  fetchUsers();
};

const handleDelete = async (id) => {
  if (window.confirm("Are you sure you want to delete this user?")) {
    await axios.delete(`http://localhost:5000/api/users/${id}`);
    fetchUsers(); // refresh list
  }
};

const filteredUsers = users.filter(u =>
  u.name.toLowerCase().includes(search.toLowerCase())
);

  return (
    <div style={{ padding: '2rem', fontFamily: 'Arial' }}>
      <h1>Users from MongoDB:</h1>
      <input
  type="text"
  placeholder="Search by name"
  value={search}
  onChange={(e) => setSearch(e.target.value)}
  style={{ marginBottom: '1rem', padding: '0.5rem', display: 'block' }}
/>
      <ul>
  {filteredUsers.map(u => (
    <li key={u._id}>
      {u.name} - {u.email}
      <button onClick={() => handleDelete(u._id)} style={{ marginLeft: '1rem' }}>❌ Delete</button>
      <button onClick={() => setEditUser(u)} style={{ marginLeft: '0.5rem' }}>✏️ Edit</button>
    </li>
  ))}
</ul>

      <h2>Add New User</h2>
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', width: '300px' }}>
    
        <input
          type="text"
          name="name"
          placeholder="Enter name"
          value={formData.name}
          onChange={handleChange}
          style={{ marginBottom: '1rem', padding: '0.5rem' }}
        />
        <input
          type="email"
          name="email"
          placeholder="Enter email"
          value={formData.email}
          onChange={handleChange}
          style={{ marginBottom: '1rem', padding: '0.5rem' }}
        />
        <button type="submit" style={{ padding: '0.5rem', cursor: 'pointer' }}>Add User</button>
      </form>
    </div>
  );
}

export default UserPage;
